"use client";

import React, { use, useState, useEffect } from "react";
import { useParams } from "next/navigation";
import {
  Upload,
  X,
  MapPin,
  Tag,
  Calendar,
  CheckCircle,
  AlertCircle,
  FileText,
} from "lucide-react";

const ClaimItemPage = ({ params }) => {
  const resolvedParams = use(params);
  const { id } = resolvedParams;
  const [loading, setLoading] = useState(true);
  const [item, setItem] = useState();

  useEffect(() => {
    const fetchItem = async () => {
      try {
        const token = localStorage.getItem("accessToken");

        const res = await fetch(`http://localhost:5000/item/details/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        const newData = await res.json();
        setItem(newData.data || newData);
        setLoading(false);
      } catch (err) {
        console.error(err);
      }
    };

    if (id) fetchItem();
  }, [id]);

  const [claimText, setClaimText] = useState("");
  const [proofImages, setProofImages] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // ==================== HANDLERS ====================
  const handleFileUpload = (e) => {
    const files = Array.from(e.target.files);

    if (files.length + proofImages.length > 3) {
      alert("Maximum 3 images allowed");
      return;
    }

    const imageFiles = files.filter((file) => file.type.startsWith("image/"));
    setProofImages([...proofImages, ...imageFiles]);
    e.target.value = null;
  };

  const removeImage = (index) => {
    setProofImages(proofImages.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!claimText.trim()) {
      alert("Please provide ownership details");
      return;
    }

    try {
      setIsSubmitting(true);

      const token = localStorage.getItem("accessToken");
      const formData = new FormData();
      formData.append("claimText", claimText);
      proofImages.forEach((img) => {
        formData.append("proofImages", img); // backend field name
      });

      const res = await fetch(
        `http://localhost:5000/report/claimItem/${id}`, //
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${token}`, //
          },
          body: formData,
        },
      );

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.message || "Claim failed");
      }

      alert("Claim submitted successfully!");
      setClaimText("");
      setProofImages([]);
    } catch (err) {
      console.error(err);
      alert(err.message || "Something went wrong");
    } finally {
      setIsSubmitting(false);
    }
  };

  // ==================== ERROR STATE ====================
  if (!item) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center p-8 bg-white rounded-lg shadow-md max-w-md">
          <AlertCircle className="w-16 h-16 text-red-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-900 mb-2">
            Item Not Found
          </h2>
          <p className="text-gray-600">Please check the URL and try again.</p>
        </div>
      </div>
    );
  }

  // ==================== RENDER ====================
  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto py-6 px-4 sm:px-6 lg:px-8">
        {/* Page Header */}
        <div className="mb-6">
          <div className="inline-block bg-indigo-800 text-white px-3 py-1 rounded text-xs font-semibold mb-2">
            Claim Submission
          </div>
          <h1 className="text-2xl font-semibold text-gray-900 mb-1">
            Claim: {item.itemName}
          </h1>
          <p className="text-sm text-gray-600">
            Please provide proof of ownership to claim this item
          </p>
        </div>

        {/* Main Content Grid */}
        <div className="grid lg:grid-cols-3 gap-6">
          {/* LEFT COLUMN - Item Details */}
          <div className="lg:col-span-2 space-y-4">
            {/* Item Image Card */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
              <div className="h-64 bg-gray-100 relative">
                <img
                  src={
                    item.photos?.[0] ||
                    "https://placehold.co/500x500/4F46E5/FFFFFF?text=Item"
                  }
                  alt={item.name}
                  className="w-full h-full object-cover"
                />
                <div className="absolute top-3 right-3 bg-white px-2 py-1 rounded text-xs font-medium text-gray-700 shadow-sm">
                  {item.category}
                </div>
              </div>
            </div>

            {/* Item Information Card */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-5">
              <h3 className="text-lg font-semibold text-gray-900 mb-3 flex items-center">
                <FileText className="w-4 h-4 mr-2 text-indigo-800" />
                Item Details
              </h3>

              {/* Description */}
              <div className="mb-4 p-3 bg-gray-50 rounded border border-gray-200">
                <p className="text-sm text-gray-700 leading-relaxed">
                  {item.description}
                </p>
              </div>

              {/* Metadata Grid */}
              <div className="grid sm:grid-cols-3 gap-3">
                <div className="flex items-center space-x-2 p-3 bg-gray-50 rounded border border-gray-200">
                  <div className="bg-indigo-800 p-1.5 rounded">
                    <Tag className="w-3.5 h-3.5 text-white" />
                  </div>
                  <div>
                    <p className="text-xs text-gray-500 font-medium">
                      Category
                    </p>
                    <p className="text-sm font-semibold text-gray-900">
                      {item.category}
                    </p>
                  </div>
                </div>

                <div className="flex items-center space-x-2 p-3 bg-gray-50 rounded border border-gray-200">
                  <div className="bg-indigo-800 p-1.5 rounded">
                    <MapPin className="w-3.5 h-3.5 text-white" />
                  </div>
                  <div>
                    <p className="text-xs text-gray-500 font-medium">
                      Location
                    </p>
                    <p className="text-sm font-semibold text-gray-900">
                      {item.location}
                    </p>
                  </div>
                </div>

                <div className="flex items-center space-x-2 p-3 bg-gray-50 rounded border border-gray-200">
                  <div className="bg-indigo-800 p-1.5 rounded">
                    <Calendar className="w-3.5 h-3.5 text-white" />
                  </div>
                  <div>
                    <p className="text-xs text-gray-500 font-medium">Date</p>
                    <p className="text-sm font-semibold text-gray-900">
                      {item.date}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* RIGHT COLUMN - Claim Form */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-5 sticky top-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Submit Your Claim
              </h2>

              <div className="space-y-4">
                {/* Claim Text Area */}
                <div>
                  <label
                    htmlFor="claimText"
                    className="block text-sm font-medium text-gray-900 mb-1.5"
                  >
                    Proof of Ownership <span className="text-red-500">*</span>
                  </label>
                  <textarea
                    id="claimText"
                    rows={4}
                    value={claimText}
                    onChange={(e) => setClaimText(e.target.value)}
                    className="w-full border border-gray-300 rounded p-3 text-sm resize-none focus:outline-none focus:border-indigo-800 focus:ring-1 focus:ring-indigo-800 transition"
                    placeholder="Describe unique features, serial numbers, or any identifying details..."
                    required
                  />
                  <p className="text-xs text-gray-500 mt-1">
                    Be specific about details only the owner would know
                  </p>
                </div>

                {/* Image Upload Section */}
                <div>
                  <label className="block text-sm font-medium text-gray-900 mb-1.5">
                    Supporting Images ({proofImages.length}/3)
                  </label>

                  {/* Upload Area */}
                  <div className="relative">
                    <input
                      type="file"
                      multiple
                      accept="image/*"
                      onChange={handleFileUpload}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                      disabled={proofImages.length >= 3}
                    />
                    <div
                      className={`border-2 border-dashed rounded p-6 text-center transition ${
                        proofImages.length >= 3
                          ? "border-gray-300 bg-gray-50 cursor-not-allowed"
                          : "border-gray-300 bg-white hover:bg-gray-50 cursor-pointer"
                      }`}
                    >
                      <Upload
                        className={`w-8 h-8 mx-auto mb-2 ${
                          proofImages.length >= 3
                            ? "text-gray-400"
                            : "text-gray-500"
                        }`}
                      />
                      <p className="text-xs font-medium text-gray-700">
                        {proofImages.length >= 3
                          ? "Maximum images uploaded"
                          : "Click or drag to upload"}
                      </p>
                      <p className="text-xs text-gray-500 mt-1">
                        PNG, JPG up to 5MB
                      </p>
                    </div>
                  </div>

                  {/* Image Previews */}
                  {proofImages.length > 0 && (
                    <div className="grid grid-cols-3 gap-2 mt-3">
                      {proofImages.map((file, idx) => (
                        <div
                          key={idx}
                          className="relative aspect-square rounded overflow-hidden border border-gray-200 bg-gray-100 group"
                        >
                          <img
                            src={URL.createObjectURL(file)}
                            alt={`Proof ${idx + 1}`}
                            className="w-full h-full object-cover"
                          />
                          <button
                            type="button"
                            onClick={() => removeImage(idx)}
                            className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition hover:bg-red-600"
                            title="Remove"
                          >
                            <X size={12} />
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                {/* Info Box */}
                <div className="bg-gray-50 border border-gray-200 rounded p-3">
                  <div className="flex items-start space-x-2">
                    <AlertCircle className="w-4 h-4 text-gray-600 flex-shrink-0 mt-0.5" />
                    <p className="text-xs text-gray-600">
                      Your claim will be reviewed by our admin team. You'll
                      receive a notification once it's processed.
                    </p>
                  </div>
                </div>

                {/* Submit Button */}
                <button
                  onClick={handleSubmit}
                  disabled={isSubmitting || !claimText.trim()}
                  className="w-full bg-indigo-800 text-white py-3 rounded font-semibold text-sm hover:bg-indigo-900 transition duration-200 flex items-center justify-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                >
                  {isSubmitting ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                      <span>Submitting...</span>
                    </>
                  ) : (
                    <>
                      <CheckCircle className="w-4 h-4" />
                      <span>Submit Claim</span>
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ClaimItemPage;
